class Bridge{public:
  Bridge(){reset();}
  void reset(){objs={{-.72f,1.25f,-2.10f,.62f,.42f,{.10f,.35f,1,.82f}},{0,1.22f,-2.05f,.58f,.38f,{1,.62f,.08f,.88f}},{.72f,1.25f,-2.10f,.58f,.38f,{.05f,.85f,.70f,.82f}}};sel=0;grab=false;hasInput=false;last=frame;px=0;py=1.1f;}
  void tick(){frame++;pulse=.5f+.5f*std::sin(frame*.08f);if(!hasInput&&frame-last>240){press("auto");release("auto");last=frame;}if(grab&&sel>=0&&sel<(int)objs.size()){objs[sel].x=clampf(px+offx,-1.15f,1.15f);objs[sel].y=clampf(py+offy,.60f,1.75f);}}
  void pointer(float x,float y){px=clampf(x,-1.25f,1.25f);py=clampf(y,.50f,1.85f);} 
  void axis(float x,float y){hasInput=true;px=clampf(px+x*.035f,-1.25f,1.25f);py=clampf(py-y*.030f,.50f,1.85f);} 
  int hit()const{for(int i=(int)objs.size()-1;i>=0;i--){auto&o=objs[(size_t)i];if(std::fabs(px-o.x)<=o.w*.6f&&std::fabs(py-o.y)<=o.h*.6f)return i;}return -1;}
  void press(const char*src){if(grab)return;hasInput=true;last=frame;int h=hit();if(h>=0){sel=h;grab=true;offx=objs[(size_t)h].x-px;offy=objs[(size_t)h].y-py;LOGI("PRESS %s grab object %d",src,h);}else{objs.push_back({px,py,-2.00f,.42f,.28f,{1,.95f,.20f,.90f}});sel=(int)objs.size()-1;grab=true;offx=offy=0;LOGI("PRESS %s created and grabbed object %d",src,sel);}}
  void release(const char*src){if(grab)LOGI("RELEASE %s drop object %d",src,sel);grab=false;last=frame;}
  std::vector<Obj>objs;int sel=0;bool grab=false,hasInput=false;float px=0,py=1.1f,pulse=0,offx=0,offy=0;unsigned long long frame=0,last=0;};

